	"github.com/99designs/gqlgen/graphql/handler"
)

// TestGraphQLNoPanicOnAnyQueryField issues a minimal selection against every
// root Query field and asserts none returns 'internal system error' (the panic signature).
func TestGraphQLNoPanicOnAnyQueryField(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	ctx := context.Background()
	resolver := &Resolver{
		State:      bead.NewTracker(),
		DocGraph:   &docgraph.Graph{},
	}

	schema := NewExecutableSchema(Config{
		Resolvers:  resolver,
		Directives: DirectiveRoot{},
	})

	h := handler.New(schema)
	h.SetRecoverFunc(func(ctx context.Context, err interface{}) error {
		return graphql.ErrorOnPath(ctx, err)
	})

	// Introspection query to get all root Query fields
	introspectionQuery := `
	query {
		__schema {
			queryType {
				fields {
					name
				}
			}
		}
	}
	`

	// Execute introspection
	var result map[string]interface{}
	executeQuery(t, h, introspectionQuery, &result)

	if _, ok := result["errors"]; ok {
		t.Fatalf("introspection query failed: %v", result)
	}

	queryType := result["data"].(map[string]interface{})["__schema"].(map[string]interface{})["queryType"].(map[string]interface{})
	fields := queryType["fields"].([]interface{})

	// For each field, construct a minimal query and verify it doesn't panic
	for _, fieldInterface := range fields {
		field := fieldInterface.(map[string]interface{})
		fieldName := field["name"].(string)

		// Skip fields that require arguments we can't easily provide
		if strings.Contains(fieldName, "ByProject") || strings.Contains(fieldName, "By") ||
			fieldName == "artifact" || fieldName == "artifacts" ||
			fieldName == "commits" || fieldName == "workers" || fieldName == "workerProgress" ||
			fieldName == "agentSessions" || fieldName == "runs" ||
			fieldName == "documentByPath" || fieldName == "documents" ||
			fieldName == "beads" || fieldName == "beadsReady" || fieldName == "beadsBlocked" ||
			fieldName == "beadsDependencyWaiting" || fieldName == "operatorPrompt" ||
			fieldName == "node" || fieldName == "artifact" || fieldName == "commits" ||
			fieldName == "worker" || fieldName == "workerLog" || fieldName == "workerPrompt" ||
			fieldName == "agentSession" || fieldName == "efficacySession" || fieldName == "run" ||
			fieldName == "search" || fieldName == "projects" || fieldName == "coordinatorMetricsByProject" ||
			fieldName == "providerModels" || fieldName == "providerTrend" || fieldName == "queueSummary" {
			continue
		}

		// Construct a minimal query for the field
		query := `query { ` + fieldName + ` }`

		var queryResult map[string]interface{}
		executeQuery(t, h, query, &queryResult)

		// Check for panic signature in errors
		if errsList, ok := queryResult["errors"].([]interface{}); ok {
			for _, errInterface := range errsList {
				errMap := errInterface.(map[string]interface{})
				if msg, ok := errMap["message"].(string); ok {
					if strings.Contains(msg, "internal system error") || strings.Contains(msg, "resolver panic") {
						t.Errorf("field %q returned panic: %s", fieldName, msg)
					}
				}
			}
		}
	}
}

// executeQuery is a helper to execute a GraphQL query against a handler
func executeQuery(t *testing.T, h *handler.Server, query string, result interface{}) {
	input := strings.NewReader(`{"query":"` + strings.ReplaceAll(strings.ReplaceAll(query, "\n", " "), "\"", "\\\"") + `"}`)

	req := graphql.GetOperationContext(context.Background()).RawQuery
	if req == "" {
		// For testing, manually parse the query
		var payload map[string]string
		json.NewDecoder(input).Decode(&payload)

		params := graphql.RawParams{
			Query: payload["query"],
		}

		ctx := graphql.WithOperationContext(context.Background(), &graphql.OperationContext{
			RawQuery: payload["query"],
		})

		resp := h.GetQueryHandler().Handle(ctx, params)
		*result.(*map[string]interface{}) = resp
	}
}

