// TestGraphQLNoPanicOnAnyQueryField tests that the SetRecoverFunc prevents
// panics from returning opaque errors. It verifies the recover function is
// active by checking that panic messages are caught and converted to GraphQL errors.
func TestGraphQLNoPanicOnAnyQueryField(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	resolver := &ddxgraphql.Resolver{
		State:    bead.NewTracker(),
		DocGraph: &docgraph.Graph{},
	}

	schema := ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers:  resolver,
		Directives: ddxgraphql.DirectiveRoot{},
	})

	h := handler.New(schema)
	h.SetRecoverFunc(func(ctx context.Context, err interface{}) error {
		return graphql.ErrorOnPath(ctx, "resolver panic: %v", err)
	})

	// Test that the Search field (which still panics) is caught by the recover func
	query := `query { search(query: "test") { edges { node { id } } } }`

	var buf bytes.Buffer
	enc := json.NewEncoder(&buf)
	enc.SetEscapeHTML(false)
	payload := map[string]string{"query": query}
	enc.Encode(payload)

	req := httptest.NewRequest("POST", "/graphql", &buf)
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	h.ServeHTTP(w, req)

	var result map[string]interface{}
	json.NewDecoder(w.Body).Decode(&result)

	// Verify that we got an error (the panic was caught)
	if _, hasErrors := result["errors"]; hasErrors {
		if errsList, ok := result["errors"].([]interface{}); ok && len(errsList) > 0 {
			errMap := errsList[0].(map[string]interface{})
			if msg, ok := errMap["message"].(string); ok {
				if strings.Contains(msg, "resolver panic") {
					// Good! The panic was caught and converted to an error
					return
				}
			}
		}
	}

	t.Errorf("expected panic to be caught by SetRecoverFunc, got: %v", result)
}

