package graphql_test

import (
	"bytes"
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
	"github.com/gorilla/websocket"
)

// TestGraphQLNoPanicOnAnyQueryField verifies that resolver panics are caught
// by SetRecoverFunc and converted to GraphQL errors, not HTTP 500 responses.
// This test uses the integration test setup with a real bead store.
func TestGraphQLNoPanicOnAnyQueryField(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	// Set up a temporary directory with a git repo and initialized bead store
	workDir := t.TempDir()
	if out, err := exec.Command("git", "init", workDir).CombinedOutput(); err != nil {
		t.Fatalf("git init: %v\n%s", err, out)
	}

	ddxDir := filepath.Join(workDir, ".ddx")
	store := bead.NewStore(ddxDir)
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}

	// Create resolver with the store
	resolver := &ddxgraphql.Resolver{
		State:      store,
		WorkingDir: workDir,
		BeadBus:    &testBeadBus{},
		Actions:    &testActionDispatcher{},
	}

	schema := ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers:  resolver,
		Directives: ddxgraphql.DirectiveRoot{},
	})

	// Build handler with SetRecoverFunc configured
	gqlServer := handler.New(schema)
	gqlServer.SetRecoverFunc(func(ctx context.Context, err interface{}) error {
		return &graphqlError{msg: err}
	})
	gqlServer.AddTransport(transport.POST{})

	// Test that a panicking field is caught and returns structured error
	// The Search field still panics since it's not in the removal list
	query := `query { search(query: "test") { edges { node { id } } } }`

	resp := executeGraphQLQuery(t, gqlServer, query)

	// Verify error was caught
	if errsList, ok := resp["errors"].([]interface{}); ok && len(errsList) > 0 {
		errMap := errsList[0].(map[string]interface{})
		if msg, ok := errMap["message"].(string); ok {
			// Check that we got a panic error, not "internal system error"
			if strings.Contains(msg, "panic") || strings.Contains(msg, "not implemented") {
				// Good! The panic was caught
				return
			}
		}
	}

	t.Errorf("expected panic to be caught by SetRecoverFunc in error message, got: %+v", resp)
}

// executeGraphQLQuery is a helper to execute a GraphQL query against a handler
func executeGraphQLQuery(t *testing.T, handler http.Handler, query string) map[string]interface{} {
	t.Helper()

	payload, _ := json.Marshal(map[string]string{"query": query})
	req := httptest.NewRequest("POST", "/graphql", bytes.NewReader(payload))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	handler.ServeHTTP(w, req)

	var result map[string]interface{}
	if err := json.NewDecoder(w.Body).Decode(&result); err != nil {
		t.Fatalf("failed to decode response: %v", err)
	}

	return result
}

// graphqlError is a custom error type that works with gqlgen
type graphqlError struct {
	msg interface{}
}

func (e *graphqlError) Error() string {
	return "panic"
}

